"use strict";const e=require("./request.js");exports.createAddress=function(s){return e.request("/addresses",{method:"POST",data:s})},exports.deleteAddress=function(s){return e.request(`/addresses/${s}`,{method:"DELETE"})},exports.getAddressList=function(){return e.request("/addresses")},exports.updateAddress=function(s,t){return e.request(`/addresses/${s}`,{method:"PUT",data:t})};
